class Person:
    def __init__(self, name):
        self.name = name

p = Person('Alice')
print(p.name)

class Dog:
    def bark(self):
        print('Woof!')

d = Dog()
d.bark()

class Book:
    def __init__(self, title):
        self.title = title

    def __str__(self):
        return self.title

b = Book('Python Basics')
print(b)

class Animal:
    def __init__(self, name):
        self.name = name

class Cat(Animal):
    def __init__(self, name, color):
        super().__init__(name)
        self.color = color

c = Cat('Tom', 'Orange')
print(c.name)

class Vector:
    def __init__(self, x, y):
        self.x = x
        self.y = y

    def __add__(self, other):
        return Vector(self.x + other.x, self.y + other.y)

    def __str__(self):
        return f'({self.x}, {self.y})'

v1 = Vector(1, 2)
v2 = Vector(3, 4)
print(v1 + v2)
